hub: upper 2 2 [zone=normal color=blue max_drones=2]
hub: lower 2 0 [zone=normal color=blue max_drones=2]
connection: hub-fork_a
connection: hub-fork_b
connection: fork_a-lower
connection: fork_a-upper
connection: fork_b-upper
connection: upper-merge
connection: lower-merge
connection: merge-goal
